253	    const conversationHistory = Array.isArray(history)
254	      ? history.slice(-8).map((m: { role: string; content: string }) => ({
255	          role: m.role === 'assistant' ? 'assistant' : 'user',
256	          content: String(m.content || '').slice(0, 1200),
257	        }))
258	      : [];
259	
260	    // Atomic rate-limit gate
261	    const { data: allowed, error: gateError } = await supabase
262	      .rpc('consume_kira_action', { p_user_id: user.id });
263	
264	    if (gateError) {
265	      console.error('Feature gate error:', gateError.message);
266	      return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
267	        status: 500, headers: cors
268	      });
269	    }
