290	    const memory = (profile?.kira_memory as Record<string, unknown>) ?? {};
291	    // deno-lint-ignore no-explicit-any
292	    const creatorProfile = (profile as any)?.creator_profiles;
293	    // deno-lint-ignore no-explicit-any
294	    const brandProfile = (profile as any)?.brand_profiles;
295	    const isCreator = profile?.user_type === 'creator';
296	
297	    const referenceMemories = memory.reference_saved_memories !== false;
298	    const referenceChatHistory = memory.reference_chat_history !== false;
299	    const activeHistory = referenceChatHistory ? conversationHistory : [];
300	
301	    // Parallel: fetch similar memories + conversation summary (only when enabled)
302	    const [memoryContext, summaryContext] = await Promise.all([
303	      referenceMemories
304	        ? fetchSimilarMemories(sanitizedPrompt, user.id, supabase)
305	        : Promise.resolve(''),
306	      referenceChatHistory && conversationId
307	        ? fetchConversationSummary(conversationId, supabase)
308	        : Promise.resolve(''),
309	    ]);
310	
311	    // Build system prompt
312	    let systemPrompt = KIRA_SYSTEM_PROMPT;
313	
314	    if (referenceMemories) {
315	      const contextLines: string[] = [
316	        `- Name: ${(memory.nickname as string) || profile?.display_name || 'not set'}`,
317	        `- Type: ${isCreator ? 'Creator' : 'Brand'}`,
318	      ];
319	      if (profile?.bio) contextLines.push(`- Bio: ${profile.bio}`);
320	      if (memory.occupation) contextLines.push(`- Occupation: ${memory.occupation}`);
321	      if (isCreator && Array.isArray(creatorProfile?.creator_types) && creatorProfile.creator_types.length > 0) {
322	        contextLines.push(`- Niche: ${(creatorProfile.creator_types as string[]).join(', ')}`);
323	      }
324	      if (isCreator && Array.isArray(creatorProfile?.goals) && creatorProfile.goals.length > 0) {
325	        contextLines.push(`- Goals: ${(creatorProfile.goals as string[]).join(', ')}`);
326	      }
327	      if (!isCreator && brandProfile?.business_type) {
328	        contextLines.push(`- Business type: ${brandProfile.business_type}`);
329	      }
330	      if (!isCreator && brandProfile?.company_description) {
331	        contextLines.push(`- Company: ${brandProfile.company_description}`);
332	      }
333	      if (memory.more_about_you) contextLines.push(`- About: ${memory.more_about_you}`);
334	
335	      systemPrompt += `\n\nUSER CONTEXT (personalise every response — do not repeat verbatim):\n${contextLines.join('\n')}`;
336	
337	      if (memoryContext) systemPrompt += `\n\n${memoryContext}`;
338	      if (memory.custom_instructions) {
339	        systemPrompt += `\n\nUSER INSTRUCTIONS (follow in all responses):\n${memory.custom_instructions}`;
340	      }
341	    }
342	
343	    // Compressed chat history replaces long raw history when summary is available
344	    if (summaryContext && activeHistory.length > 4) {
345	      systemPrompt += `\n\n${summaryContext}`;
346	    }
347	
348	    // Build LangChain message list
349	    const langchainMessages = [
350	      new SystemMessage(systemPrompt),
351	      ...(summaryContext && activeHistory.length > 4
352	        ? activeHistory.slice(-4)   // keep only 4 most recent turns when summary covers the rest
353	        : activeHistory
354	      ).map(m => m.role === 'user' ? new HumanMessage(m.content) : new AIMessage(m.content)),
355	      new HumanMessage(sanitizedPrompt),
356	    ];
357	
358	    // Stream response
359	    const { readable, writable } = new TransformStream<Uint8Array, Uint8Array>();
360	    const writer = writable.getWriter();
361	    const encoder = new TextEncoder();
362	
363	    let fullResponse = '';
364	
365	    const pump = async () => {
366	      try {
367	        const stream = await llm.stream(langchainMessages);
368	        for await (const chunk of stream) {
369	          const token = typeof chunk.content === 'string' ? chunk.content : '';
370	          if (token) {
371	            fullResponse += token;
372	            await writer.write(encoder.encode(token));
373	          }
374	        }
375	      } finally {
376	        await writer.close().catch(() => {});
377	
378	        // Fire-and-forget: extract long-term memories from this exchange
379	        if (referenceMemories && fullResponse) {
380	          extractAndStoreMemories(sanitizedPrompt, fullResponse, user.id, supabase)
381	            .catch(e => console.warn('[Kira] Memory extraction failed:', e));
382	        }
383	
384	        // Fire-and-forget: update conversation summary when there are enough turns
385	        if (conversationId && fullResponse && activeHistory.length >= 4) {
386	          updateConversationSummary(
387	            conversationId,
388	            user.id,
389	            [
390	              ...activeHistory,
391	              { role: 'user', content: sanitizedPrompt },
392	              { role: 'assistant', content: fullResponse },
393	            ],
394	            supabase
395	          ).catch(e => console.warn('[Kira] Summary update failed:', e));
396	        }
397	      }
398	    };
399	
400	    pump();
401	
402	    return new Response(readable, {
403	      headers: {
404	        ...cors,
405	        'Content-Type': 'text/plain; charset=utf-8',
406	        'Cache-Control': 'no-cache',
407	        'X-Accel-Buffering': 'no',
408	      },
409	    });
410	
411	  } catch (error: unknown) {
412	    const msg = error instanceof Error ? error.message : String(error);
413	    console.error("Function Error:", msg);
414	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
415	      status: 500, headers: cors
416	    });
417	  }
418	});
