    { key: "failed" as SecurityFilter,  label: "Failed Attempts",  value: failed.length,                color: failed.length > 0 ? "text-red-400" : "text-white/30", border: "border-red-400/40" },
  ];

  return (
    <div className="p-4 md:p-6 space-y-6 max-w-4xl">
